@Service
class SearchService {

    private static final String PRODUCT_INDEX = "products";
    private static final String QUERY_INDEX = "customer_search_queries";

    private final RestHighLevelClient client;

    SearchService(RestHighLevelClient client) {
        this.client = client;
    }

    public SearchResponseDto searchProducts(ProductSearchRequest request) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            MultiMatchQueryBuilder multiMatchQuery = QueryBuilders.multiMatchQuery(request.getQuery(), "name^3", "description^2", "brand", "category")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness(Fuzziness.AUTO);
            boolQuery.must(multiMatchQuery);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }

        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }

        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            if (request.getMinPrice() != null && request.getMaxPrice() != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").gte(request.getMinPrice()).lte(request.getMaxPrice()));
            } else if (request.getMinPrice() != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").gte(request.getMinPrice()));
            } else {
                boolQuery.filter(QueryBuilders.rangeQuery("price").lte(request.getMaxPrice()));
            }
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(request.getPage() * request.getSize());
        sourceBuilder.size(request.getSize());

        sourceBuilder.aggregation(AggregationBuilders.terms("categories").field("category").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("brands").field("brand").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("tags").field("tags").size(20));

        searchRequest.source(sourceBuilder);
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<ProductDocument> products = Arrays.stream(response.getHits().getHits())
                .map(this::toProductDocument)
                .collect(Collectors.toList());

        Map<String, List<FacetBucket>> facets = new HashMap<>();
        ParsedStringTerms categories = response.getAggregations().get("categories");
        ParsedStringTerms brands = response.getAggregations().get("brands");
        ParsedStringTerms tags = response.getAggregations().get("tags");

        facets.put("categories", categories.getBuckets().stream()
                .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                .collect(Collectors.toList()));
        facets.put("brands", brands.getBuckets().stream()
                .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                .collect(Collectors.toList()));
        facets.put("tags", tags.getBuckets().stream()
                .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                .collect(Collectors.toList()));

        logSearchQuery(request, Math.toIntExact(response.getHits().getTotalHits().value));

        SearchResponseDto dto = new SearchResponseDto();
        dto.setProducts(products);
        dto.setFacets(facets);
        dto.setTotalHits(response.getHits().getTotalHits().value);
        dto.setPage(request.getPage());
        dto.setSize(request.getSize());
        return dto;
    }

    private void logSearchQuery(ProductSearchRequest request, int resultCount) throws IOException {
        Map<String, Object> queryDoc = new HashMap<>();
        queryDoc.put("query", request.getQuery());
        queryDoc.put("category", request.getCategory());
        queryDoc.put("brand", request.getBrand());
        queryDoc.put("minPrice", request.getMinPrice());
        queryDoc.put("maxPrice", request.getMaxPrice());
        queryDoc.put("searchedAt", Instant.now().toString());
        queryDoc.put("resultCount", resultCount);

        IndexRequest indexRequest = new IndexRequest(QUERY_INDEX)
                .id(UUID.randomUUID().toString())
                .source(queryDoc);
        client.index(indexRequest, RequestOptions.DEFAULT);
    }

    private ProductDocument toProductDocument(SearchHit hit) {
        Map<String, Object> source = hit.getSourceAsMap();
        ProductDocument doc = new ProductDocument();
        doc.setId(hit.getId());
        doc.setName(asString(source.get("name")));
        doc.setDescription(asString(source.get("description")));
        doc.setCategory(asString(source.get("category")));
        doc.setBrand(asString(source.get("brand")));
        doc.setPrice(asBigDecimal(source.get("price")));
        doc.setCurrency(asString(source.get("currency")));
        doc.setCreatedAt(asString(source.get("createdAt")));

        Object tags = source.get("tags");
        if (tags instanceof List) {
            doc.setTags(((List<?>) tags).stream().map(String::valueOf).collect(Collectors.toList()));
        } else {
            doc.setTags(Collections.emptyList());
        }

        Object attributes = source.get("attributes");
        if (attributes instanceof Map) {
            doc.setAttributes((Map<String, Object>) attributes);
        } else {
            doc.setAttributes(Collections.emptyMap());
        }
        return doc;
    }

    private String asString(Object value) {
        return value == null ? null : String.valueOf(value);
    }

    private BigDecimal asBigDecimal(Object value) {
        return value == null ? null : new BigDecimal(String.valueOf(value));
    }
}

